  `nTipoPessoa` int(11) DEFAULT NULL,
  `aInscricaoEstadual` varchar(30) DEFAULT NULL,
  `email` varchar(128) DEFAULT NULL,
  `aHomePage` varchar(128) DEFAULT NULL,
  `nIdCidade` int(11) DEFAULT NULL,
  `nCEP` int(11) DEFAULT NULL,
  `aRespNome` varchar(40) DEFAULT NULL,
