  `aDiretorio` varchar(128) NOT NULL,
  `aNomeBancoDados` varchar(128) NOT NULL,
  `aUsuarioBanco` varchar(128) NOT NULL,
  `aSenhaBanco` varchar(128) DEFAULT NULL,
  `nSistemas` int(11) DEFAULT NULL,
  `nBinOpcoes` int(11) DEFAULT NULL,
  `nBinSerrvicos` int(11) DEFAULT NULL,
  `aNroSerie` varchar(10) DEFAULT NULL,
  `nEspacoParaBD` bigint(20) DEFAULT NULL,
  `nEspacoEmHD` bigint(20) DEFAULT NULL,
  `dtDataCriacao` date NOT NULL,
  `dtDataExclusao` date DEFAULT NULL,
  `aLogo` varchar(128) DEFAULT NULL,
  `nQtdContratosAtivos` int(11) DEFAULT NULL,
  `nQtdAcessoSimultaneo` int(11) DEFAULT NULL,
  `nTempoDaSessao` int(11) DEFAULT NULL,
  `aJsonCdAdm` text DEFAULT NULL,
  `aJsonCdFin` text DEFAULT NULL,
  `aJsonCamposParticulares` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`aJsonCamposParticulares`)),
  `nStatus` int(11) DEFAULT 0,
  `nIdLoginIncluiu` int(11) DEFAULT NULL,
  `dDataIncluiu` datetime DEFAULT NULL,
  `nIdLoginAlterou` int(11) DEFAULT NULL,
  `dDataAlterou` datetime DEFAULT NULL,
  `nIdLoginExcluiu` int(11) DEFAULT NULL,
